// Prepara i dati per l'invio al JotForm carrello
// Form ID: 260832964392061
const input = $input.first().json.body || $input.first().json;
const selezioni = input.selezioni || [];
const brief = input.brief || {};

// Struttura per JotForm Products/Cart
// JotForm usa un formato specifico per i campi prodotto nel carrello
// Il campo prodotto ha sottocampi: nome, prezzo, quantità, descrizione

// Prepara gli items del carrello
const cartItems = selezioni.map((sel, index) => {
  return {
    categoria: sel.categoria,
    nome: sel.nome,
    descrizione: sel.descrizione || '',
    prezzo: sel.costo_reale || sel.prezzo_stimato || 0,
    quantita: sel.quantita || 1,
    note: sel.note || '',
    fornitore_confermato: sel.fornitore_confermato || false
  };
});

// Calcola totali
const totale = cartItems.reduce((sum, item) => sum + (item.prezzo * item.quantita), 0);

return {
  json: {
    brief: brief,
    cartItems: cartItems,
    totale: totale,
    progetto_id: input.progetto_id
  }
};

// Costruisci il payload per JotForm API
// Endpoint: https://api.jotform.com/form/260832964392061/submissions
const input = $input.first().json;
const cartItems = input.cartItems;
const brief = input.brief;

// ===============================================
// IMPORTANTE: Prima di usare questo workflow,
// esegui questa chiamata per scoprire gli ID reali dei campi:
// GET https://api.jotform.com/form/260832964392061/questions?apiKey=TUA_API_KEY
//
// Poi sostituisci i numeri dei campi qui sotto con quelli reali.
// In particolare, trova il campo di tipo 'control_payment' 
// per il carrello prodotti e usa il suo ID al posto di CART_FIELD_ID.
// ===============================================

const submission = {};

// Campi informativi base (ADATTA GLI ID ai campi reali del tuo form)
submission['submission[3]'] = brief.nome_evento || '';
submission['submission[4]'] = brief.nome_cliente || '';
submission['submission[5]'] = brief.data_evento || '';
submission['submission[6]'] = brief.numero_partecipanti || '';

// Campo prodotto/carrello JotForm
// FORMATO CORRETTO per campi payment/cart JotForm:
// submission[FIELD_ID_paymentArray_products][N] = nome prodotto
// submission[FIELD_ID_paymentArray_price][N]    = prezzo
// submission[FIELD_ID_paymentArray_quantity][N]  = quantità
//
// SOSTITUISCI 'CART_FIELD_ID' con l'ID reale del campo carrello
// trovato nella risposta di GET /form/260832964392061/questions

const CART_FIELD_ID = '10'; // <-- CAMBIA con l'ID reale del campo carrello

cartItems.forEach((item, index) => {
  submission[`submission[${CART_FIELD_ID}_paymentArray_products][${index}]`] = `[${item.categoria}] ${item.nome}`;
  submission[`submission[${CART_FIELD_ID}_paymentArray_price][${index}]`] = item.prezzo;
  submission[`submission[${CART_FIELD_ID}_paymentArray_quantity][${index}]`] = item.quantita || 1;
});

// Totale (calcolato anche automaticamente da JotForm)
const totale = cartItems.reduce((sum, item) => sum + (item.prezzo * (item.quantita || 1)), 0);
submission[`submission[${CART_FIELD_ID}_paymentArray_total]`] = totale;
submission[`submission[${CART_FIELD_ID}_paymentArray_currency]`] = 'EUR';

return {
  json: {
    form_id: '260832964392061',
    submission: submission,
    cartItems: cartItems,
    totale: totale,
    progetto_id: input.progetto_id
  }
};

// Verifica risultato invio e aggiorna lo stato del progetto
const input = $input.first().json;
const progettoId = $('Mappa Campi JotForm').first().json.progetto_id;

const staticData = $getWorkflowStaticData('global');

if (staticData.progetti && staticData.progetti[progettoId]) {
  staticData.progetti[progettoId].stato = 'inviato';
  staticData.progetti[progettoId].jotform_submission_id = input.content?.submissionID || null;
  staticData.progetti[progettoId].storico.push({
    data: new Date().toISOString(),
    azione: 'Proposte inviate al JotForm carrello',
    utente: 'sistema',
    jotform_response: input
  });

  // Aggiorna indice
  if (staticData.indice_progetti) {
    const idx = staticData.indice_progetti.findIndex(p => p.id === progettoId);
    if (idx >= 0) {
      staticData.indice_progetti[idx].stato = 'inviato';
    }
  }
}

return {
  json: {
    success: input.responseCode === 200 || input.content?.submissionID,
    message: input.content?.submissionID 
      ? `Invio riuscito! Submission ID: ${input.content.submissionID}`
      : 'Invio completato - verifica su JotForm',
    submission_id: input.content?.submissionID || null,
    progetto_id: progettoId
  }
};
